sql:
SELECT name
FROM individuals
ORDER BY name;

SELECT name
FROM individuals
WHERE net_worth = (SELECT MAX(net_worth) FROM individuals);

SELECT name
FROM individuals
ORDER BY rank;

SELECT name
FROM individuals
ORDER BY rank;

SELECT individual_id, MAX(date) AS latest_date
FROM net_worth_history
GROUP BY individual_id;

external_knowledge:
- "Top 10 ranked individuals" refers to those with the lowest rank number, assuming rank 1 is the highest; 
- "Net worth exceeding $1 billion" means the value is greater than 1,000,000,000 USD; 
- "Average revenue exceeding $100 million" means the value is greater than 100,000,000 USD.
